package com.example.app.waitlist; import com.example.app.common.BaseEntity; import com.example.app.company.Company; import com.example.app.session.SessionBooking; import com.example.app.user.User; import jakarta.persistence.*; import lombok.Getter; import lombok.Setter; import java.time.*; @Getter @Setter @Entity @Table(name="waitlist_offer") public class WaitlistOffer extends BaseEntity { @ManyToOne(optional=false) @JoinColumn(name="company_id") private Company company; @ManyToOne(optional=false) @JoinColumn(name="waitlist_request_id") private WaitlistRequest request; @Column(name="slot_start",nullable=false) private LocalDateTime slotStart; @Column(name="slot_end",nullable=false) private LocalDateTime slotEnd; @ManyToOne @JoinColumn(name="employee_id") private User employee; @Column(name="room_id") private Long roomId; @ManyToOne @JoinColumn(name="session_id") private SessionBooking session; @Column(nullable=false,length=32) private String status="PENDING"; @Column(name="offered_at",nullable=false) private LocalDateTime offeredAt=LocalDateTime.now(); @Column(name="expires_at",nullable=false) private LocalDateTime expiresAt; @Column(name="accepted_at") private LocalDateTime acceptedAt; @Column(name="declined_at") private LocalDateTime declinedAt; @ManyToOne @JoinColumn(name="booking_hold_id") private BookingHold bookingHold; @Column(name="secure_token_hash",length=128) private String secureTokenHash; @Version private Long version; }